947	      />
948	    );
949	  if (mode === 'section') return <SectionModeShell elementsById={elementsById} />;
950	  if (mode === 'sheet') return <SheetModeShell elementsById={elementsById} />;
951	  if (mode === 'schedule') return <ScheduleModeShell elementsById={elementsById} />;
952	  if (mode === 'agent') return <AgentReviewModeShell />;
953	  return viewerMode === 'orbit_3d' ? (
954	    <Viewport wsConnected={false} />
955	  ) : (
956	    <PlanCanvas
957	      wsConnected={false}
958	      activeLevelResolvedId={activeLevelId}
959	      onSemanticCommand={onSemanticCommand}
960	    />
961	  );
962	}
963	
964	function EmptyStateOverlay({
965	  headline,
966	  hint,
967	  ctaLabel,
968	  ctaPending,
969	  ctaError,
970	  onCta,
971	}: {
972	  headline: string;
973	  hint: string;
974	  ctaLabel: string | null;
975	  ctaPending: boolean;
976	  ctaError: string | null;
977	  onCta: () => void;
978	}): JSX.Element {
979	  return (
980	    <div
981	      role="status"
982	      aria-live="polite"
983	      style={{
984	        position: 'absolute',
985	        inset: 0,
986	        zIndex: 5,
987	        display: 'flex',
988	        alignItems: 'center',
989	        justifyContent: 'center',
990	        pointerEvents: 'none',
991	      }}
992	    >
993	      <div className="pointer-events-auto flex flex-col items-center gap-3 rounded-lg bg-surface/95 px-6 py-5 text-center shadow-elev-2 backdrop-blur">
994	        <div className="text-md font-medium text-foreground">{headline}</div>
995	        <div className="text-sm text-muted">{hint}</div>
996	        {ctaLabel ? (
997	          <button
998	            type="button"
999	            onClick={onCta}
1000	            disabled={ctaPending}
1001	            data-testid="canvas-empty-cta"
1002	            className="rounded-md bg-accent px-4 py-1.5 text-sm font-medium text-accent-foreground shadow-elev-1 hover:bg-accent/90 disabled:cursor-not-allowed disabled:opacity-60"
1003	          >
1004	            {ctaPending ? 'Loading…' : ctaLabel}
1005	          </button>
1006	        ) : null}
1007	        {ctaError ? (
1008	          <div className="text-xs text-danger" data-testid="canvas-empty-error">
1009	            {ctaError}
1010	          </div>
1011	        ) : null}
1012	      </div>
1013	    </div>
1014	  );
1015	}
1016	
1017	function InspectorEmptyTab({ message }: { message: string }): JSX.Element {
1018	  return <p className="text-sm text-muted">{message}</p>;
1019	}
1020	
1021	function humanKindLabel(kind: string): string {
1022	  return kind.replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
1023	}
1024	
1025	/** Default tab descriptor when a mode pill (or tab `+`) is clicked
1026	 * with no specific element. Picks the active level for plan/plan-3d,
1027	 * the first viewpoint for 3d, the first section for section, etc. */
1028	function defaultTabFallbackForKind(
1029	  kind: WorkspaceMode | TabKind,
1030	  elementsById: Record<string, Element>,
1031	  activeLevelId: string | undefined,
1032	): { targetId?: string; label: string } | null {
1033	  const all = Object.values(elementsById) as Element[];
1034	  if (kind === 'plan' || kind === 'plan-3d') {
1035	    const levels = all
1036	      .filter((e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level')
1037	      .sort((a, b) => a.elevationMm - b.elevationMm);
1038	    const lvl = levels.find((l) => l.id === activeLevelId) ?? levels[0];
1039	    if (!lvl) return { label: kind === 'plan' ? 'Plan' : 'Plan + 3D' };
1040	    return {
1041	      targetId: lvl.id,
1042	      label: kind === 'plan' ? `Plan · ${lvl.name}` : `Plan + 3D · ${lvl.name}`,
1043	    };
1044	  }
1045	  if (kind === '3d') {
1046	    const vp = all.find(
1047	      (e): e is Extract<Element, { kind: 'viewpoint' }> => e.kind === 'viewpoint',
1048	    );
1049	    if (vp) return { targetId: vp.id, label: `3D · ${vp.name}` };
1050	    return { label: '3D · Default' };
1051	  }
1052	  if (kind === 'section') {
1053	    const sec = all.find(
1054	      (e): e is Extract<Element, { kind: 'section_cut' }> => e.kind === 'section_cut',
1055	    );
1056	    if (sec) return { targetId: sec.id, label: `Section · ${sec.name}` };
1057	    return { label: 'Section' };
1058	  }
1059	  if (kind === 'sheet') {
1060	    const sht = all.find((e): e is Extract<Element, { kind: 'sheet' }> => e.kind === 'sheet');
1061	    if (sht) return { targetId: sht.id, label: `Sheet · ${sht.name}` };
1062	    return { label: 'Sheet' };
1063	  }
1064	  if (kind === 'schedule') {
1065	    const s = all.find((e): e is Extract<Element, { kind: 'schedule' }> => e.kind === 'schedule');
1066	    if (s) return { targetId: s.id, label: `Schedule · ${s.name}` };
1067	    return { label: 'Schedule' };
1068	  }
1069	  if (kind === 'agent') {
1070	    return { label: 'Agent review' };
1071	  }
1072	  return null;
