11	/**
12	 * Mode-specific shells — spec §20.4 / §20.5 / §20.6 / §20.7.
13	 *
14	 * These render the canvas-region content for the four E-WPs. The
15	 * RedesignedWorkspace selects the right shell by `mode`. Each shell
16	 * pulls its data from `useBimStore` so the redesign tracks live state.
17	 *
18	 * The shells are intentionally light: structural surfaces (Project
19	 * Browser, viewport mounts) and readout content from the seed-house
20	 * fixture; richer interactions (drag/resize, inline edit) follow with
21	 * the canvas drawing flow.
22	 */
23	
24	function asArr<T extends Element['kind']>(
25	  elementsById: Record<string, Element>,
26	  k: T,
27	): Extract<Element, { kind: T }>[] {
28	  return (Object.values(elementsById) as Element[]).filter(
29	    (e): e is Extract<Element, { kind: T }> => e.kind === k,
30	  );
31	}
