        <div
          className="text-xs uppercase text-muted"
          style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
        >
          Section cuts
        </div>
        {sections.length === 0 ? (
          <p className="text-sm text-muted">No section cuts in the document.</p>
