    </div>
  );
}

function SectionPreview({
  section,
}: {
  section: Extract<Element, { kind: 'section_cut' }>;
}): JSX.Element {
  return (
    <div className="flex flex-1 flex-col gap-3 px-4 py-4 text-sm">
      <div className="text-md font-medium text-foreground">{section.name}</div>
