              Rows hydrate from the server `derive_schedule_table` endpoint.
            </td>
            <td className="border-b border-border px-2 py-1.5 text-right text-muted">—</td>
            <td className="border-b border-border px-2 py-1.5 text-right text-muted">—</td>
          </tr>
        </tbody>
      </table>
    </div>
  );
